1	// ── Saga Orchestrator ───────────────────────────────────────────────────────
2	
3	export type SagaStatus = 'pending' | 'running' | 'completed' | 'failed' | 'compensating';
4	
5	export interface SagaStep {
6	  name: string;
7	  execute: () => void | Promise<void>;
8	  compensate: () => void | Promise<void>;
9	}
10	
11	export interface SagaDefinition {
12	  name: string;
13	  steps: SagaStep[];
14	  timeout?: number; // ms, default 30000
15	}
16	
17	export interface SagaInstance {
18	  id: string;
19	  definitionName: string;
20	  status: SagaStatus;
21	  currentStep: number;
22	  completedSteps: string[];
23	  failedStep: string | null;
24	  compensatedSteps: string[];
25	  error: string | null;
26	  startedAt: number;
27	  completedAt: number | null;
28	}
29	
30	export class SagaError extends Error {
31	  constructor(message: string, public readonly sagaId: string) {
32	    super(message);
33	    this.name = 'SagaError';
34	  }
35	}
36	
37	export function createSagaOrchestrator(): {
38	  register(definition: SagaDefinition): void;
39	  start(definitionName: string, sagaId: string): Promise<SagaInstance>;
40	  getInstance(sagaId: string): SagaInstance | null;
41	  getInstancesByDefinition(definitionName: string): SagaInstance[];
42	  getActiveSagaCount(): number;
43	} {
44	  const definitions = new Map<string, SagaDefinition>();
45	  const instances = new Map<string, SagaInstance>();
46	
47	  async function compensate(instance: SagaInstance, definition: SagaDefinition): Promise<void> {
48	    instance.status = 'compensating';
49	
50	    // Compensate in reverse order of completed steps
51	    const stepsToCompensate = [...instance.completedSteps].reverse();
52	
53	    for (const stepName of stepsToCompensate) {
54	      const step = definition.steps.find(s => s.name === stepName);
55	      if (step) {
56	        try {
57	          await step.compensate();
58	          instance.compensatedSteps.push(stepName);
59	        } catch (compError: any) {
60	          // Record compensation error but continue compensating remaining steps
61	          instance.error = `Compensation failed for step '${stepName}': ${compError.message ?? String(compError)}; Original error: ${instance.error}`;
62	        }
63	      }
64	    }
65	
66	    instance.status = 'failed';
67	    instance.completedAt = Date.now();
68	  }
69	
70	  return {
71	    register(definition: SagaDefinition): void {
72	      if (definitions.has(definition.name)) {
73	        throw new SagaError(
74	          `Saga definition '${definition.name}' is already registered`,
75	          '',
76	        );
77	      }
78	      definitions.set(definition.name, definition);
79	    },
80	
81	    async start(definitionName: string, sagaId: string): Promise<SagaInstance> {
82	      const definition = definitions.get(definitionName);
83	      if (!definition) {
84	        throw new SagaError(
85	          `Saga definition '${definitionName}' is not registered`,
86	          sagaId,
87	        );
88	      }
89	
90	      if (instances.has(sagaId)) {
91	        throw new SagaError(
92	          `Saga instance '${sagaId}' already exists`,
93	          sagaId,
94	        );
95	      }
96	
97	      const instance: SagaInstance = {
98	        id: sagaId,
99	        definitionName,
100	        status: 'running',
101	        currentStep: 0,
102	        completedSteps: [],
103	        failedStep: null,
104	        compensatedSteps: [],
105	        error: null,
106	        startedAt: Date.now(),
107	        completedAt: null,
108	      };
109	
110	      instances.set(sagaId, instance);
111	
112	      const timeout = definition.timeout ?? 30000;
113	
114	      // Create a timeout race
115	      let timedOut = false;
116	      const timeoutPromise = new Promise<'timeout'>((resolve) => {
117	        setTimeout(() => {
118	          timedOut = true;
119	          resolve('timeout');
120	        }, timeout);
121	      });
122	
123	      const executeSteps = async (): Promise<'done'> => {
124	        for (let i = 0; i < definition.steps.length; i++) {
125	          if (timedOut) break;
126	
127	          const step = definition.steps[i];
128	          instance.currentStep = i;
129	
130	          try {
131	            await step.execute();
132	            instance.completedSteps.push(step.name);
133	          } catch (err: any) {
134	            instance.failedStep = step.name;
135	            instance.error = err.message ?? String(err);
136	            await compensate(instance, definition);
137	            return 'done';
138	          }
139	        }
140	        return 'done';
141	      };
142	
143	      const result = await Promise.race([executeSteps(), timeoutPromise]);
144	
145	      if (result === 'timeout' && instance.status === 'running') {
146	        instance.failedStep = definition.steps[instance.currentStep]?.name ?? null;
147	        instance.error = `Saga timed out after ${timeout}ms`;
148	        await compensate(instance, definition);
149	        return instance;
150	      }
151	
152	      // If we completed all steps without failure or timeout
153	      if (instance.status === 'running') {
154	        instance.status = 'completed';
155	        instance.completedAt = Date.now();
156	      }
157	
158	      return instance;
159	    },
160	
161	    getInstance(sagaId: string): SagaInstance | null {
162	      return instances.get(sagaId) ?? null;
163	    },
164	
165	    getInstancesByDefinition(definitionName: string): SagaInstance[] {
166	      const result: SagaInstance[] = [];
167	      for (const inst of instances.values()) {
168	        if (inst.definitionName === definitionName) {
169	          result.push(inst);
170	        }
171	      }
172	      return result;
173	    },
174	
175	    getActiveSagaCount(): number {
176	      let count = 0;
177	      for (const inst of instances.values()) {
178	        if (inst.status === 'running' || inst.status === 'compensating') {
179	          count++;
180	        }
181	      }
182	      return count;
183	    },
184	  };
185	}
